import React from 'react';
import c from './workers.module.scss';
import { periods } from '../../utils';
import { Icons } from '../../assets/icons';
import { API } from '../../api';
import { Components } from '..';

const ClientsTable = () => {
  const [month, setMonth] = React.useState('');
  const [clients, setClients] = React.useState(null);
  const [active, setActive] = React.useState(false);
  const [selectedWeek, setSelectedWeek] = React.useState(5); // по умолчанию "Весь месяц"

  const months = [
    "Январь", "Февраль", "Март", "Апрель", "Май", "Июнь",
    "Июль", "Август", "Сентябрь", "Октябрь", "Ноябрь", "Декабрь"
  ];

  const currentDate = new Date();
  const currentYear = currentDate.getFullYear();
  const currentMonth = currentDate.getMonth();

  React.useEffect(() => {
    const monthName = currentDate.toLocaleString('ru', { month: 'long' });
    setMonth(monthName.charAt(0).toUpperCase() + monthName.slice(1));

    API.getClients()
      .then(res => {
        const data = Object.keys(res.data).map(key => ({
          ...res.data[key],
          id: key,
        }));
        setClients(data);
      });
  }, []);

  const formatDate = (dateString) => {
    const date = new Date(dateString);
    const day = date.getDate();
    const month = date.toLocaleString('ru-RU', { month: 'long' });
    return `${day} ${month}`;
  };

  return (
    <div className={c.workers}>
      <div className={c.title}>
        <div className={c.left}>
          <button onClick={() => setActive(true)}>
            + Добавить
          </button>
          <div className={c.search}>
            <img src={Icons.search} alt="search" />
            <input type="text" placeholder="Найти клиентов" />
          </div>
        </div>
        <div className={c.right}>
          <div className={c.date}>
            <span>{month}</span>
            <button>Выбрать месяц</button>
          </div>
          <span className={c.line}></span>
          <div className={c.periods}>
            {periods.map(item => (
              <button
                key={item.id}
                className={selectedWeek === item.id ? c.active : ''}
                onClick={() => setSelectedWeek(item.id)}
              >
                {item.title}
              </button>
            ))}
          </div>
        </div>
      </div>

      <div className={c.table}>
        <table>
          <thead>
            <tr>
              <th><img src={Icons.edit} alt="edit" /></th>
              <th>Дата</th>
              <th>Ф.И.О клиента</th>
              <th>Телефон</th>
              <th className={c.services}>Процедуры</th>
              <th>Сотрудник</th>
              <th>Прайс по итогу</th>
            </tr>
          </thead>
          <tbody>
            {filteredClients?.length !== 0 ? filteredClients.map(item => (
              <tr key={item.id}>
                <td>
                  <img src={Icons.edit} alt="edit" />
                </td>
                <td>
                  <div className={c.date}>{formatDate(item.appointment_date)}</div>
                  <div className={c.date}>{item.master?.time}</div>
                </td>
                <td>{item.name}</td>
                <td>{item.phone}</td>
                <td className={c.services}>
                  {item?.services?.map((value, idx) => (
                    <div key={idx} className={c.service}>
                      {value.name}
                    </div>
                  ))}
                </td>
                <td>
                  <div className={c.worker}>
                    {item.master?.name}
                  </div>
                </td>
                <td>
                  {Array.isArray(item?.services)
                    ? item.services.reduce((sum, obj) => sum + Number(obj.price || 0), 0)
                    : 0}
                </td>
              </tr>
            )) : (
              <tr>
                <td><img src={Icons.edit} alt="edit" /></td>
                <td>Клиентов нет</td>
                <td></td><td></td><td className={c.services}></td><td></td><td></td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {active && <Components.AddClient setActive={setActive} />}
    </div>
  );
};

export default ClientsTable;
